-- =============================================================================
-- seed_fixture.sql — Torneo, grupos, partidos fase de grupos — Mundial 2026
-- Ejecutar contra fixture_db después de correr las migraciones.
-- Uso: psql -U wc2026 -d fixture_db -f seed_fixture.sql
--
-- Sorteo oficial FIFA Mundial 2026 (diciembre 2025)
-- Schedule: 11 junio – 19 julio 2026
-- =============================================================================

-- Limpiar datos previos (cascade elimina todo lo dependiente)
TRUNCATE TABLE fixture_events    RESTART IDENTITY CASCADE;
TRUNCATE TABLE match_results     RESTART IDENTITY CASCADE;
TRUNCATE TABLE group_standings   RESTART IDENTITY CASCADE;
TRUNCATE TABLE matches           RESTART IDENTITY CASCADE;
TRUNCATE TABLE group_teams       RESTART IDENTITY CASCADE;
TRUNCATE TABLE groups            RESTART IDENTITY CASCADE;
TRUNCATE TABLE tournaments       RESTART IDENTITY CASCADE;

