-- =============================================================================
-- 4. STANDINGS INICIALES (todos en 0 — se actualizan al registrar resultados)
-- =============================================================================

INSERT INTO group_standings (group_id, team_id, position, played, won, drawn, lost, goals_for, goals_against, yellow_cards, red_cards)
SELECT gt.group_id, gt.team_id,
       ROW_NUMBER() OVER (PARTITION BY gt.group_id ORDER BY gt.seeding_pot),
       0,0,0,0,0,0,0,0
FROM group_teams gt;

