-- =============================================================================
-- 6. VERIFICACIÓN
-- =============================================================================
DO $$
DECLARE
    total_matches  INT;
    total_groups   INT;
    total_teams    INT;
    total_standings INT;
BEGIN
    SELECT COUNT(*) INTO total_matches   FROM matches  WHERE phase = 'GROUP';
    SELECT COUNT(*) INTO total_groups    FROM groups;
    SELECT COUNT(*) INTO total_teams     FROM group_teams;
    SELECT COUNT(*) INTO total_standings FROM group_standings;

    RAISE NOTICE '=== Verificación seed_fixture ===';
    RAISE NOTICE 'Grupos             : %  (esperado: 12)',  total_groups;
    RAISE NOTICE 'Equipos en grupos  : %  (esperado: 48)',  total_teams;
    RAISE NOTICE 'Partidos de grupo  : %  (esperado: 72)',  total_matches;
    RAISE NOTICE 'Standings iniciales: %  (esperado: 48)',  total_standings;

    IF total_groups    != 12 THEN RAISE EXCEPTION 'Error: grupos = %',    total_groups;    END IF;
    IF total_teams     != 48 THEN RAISE EXCEPTION 'Error: equipos = %',   total_teams;     END IF;
    IF total_matches   != 72 THEN RAISE EXCEPTION 'Error: partidos = %',  total_matches;   END IF;
    IF total_standings != 48 THEN RAISE EXCEPTION 'Error: standings = %', total_standings; END IF;

    RAISE NOTICE '✅ seed_fixture completado correctamente.';
END $$;
